#include <bits/stdc++.h>
using namespace std;
int n,a,b,k[202],dis[202];
void bfs(){
    queue<int> q;
    q.push(a),dis[a]=1;
    while(q.size()){
        int f=q.front();
        q.pop();
        if(f-k[f]>0 && !dis[f-k[f]]){
            dis[f-k[f]]=dis[f]+1;
            q.push(f-k[f]);
        }
        if(f+k[f]<=n && !dis[f+k[f]]){
            dis[f+k[f]]=dis[f]+1;
            q.push(f+k[f]);
        }
    }
    cout<<dis[b]-1;
}
int main(){
    cin>>n>>a>>b;
    for(int i=1;i<=n;i++)
        cin>>k[i];
    bfs();
    return 0;
}
